export const ERRORS = Object.freeze({
  NONE: 0,
  UNAUTHORIZED: 1,
  CORRUPTED_ARCHIVE: 2,
  UNSUPPORTED_BACKUP_VERSION: 3,
  UNINITIALIZED: 4,
  FILE_SYSTEM_ERROR: 5,
  ENCRYPTION_FAILED: 6,
  DECRYPTION_FAILED: 7,
  RECOVERY_FAILED: 8,
  UNKNOWN: 9,
  ENCRYPTION_ALREADY_ENABLED: 10,
  ENCRYPTION_ALREADY_DISABLED: 11,
  INVALID_PASSWORD: 12,
  INTERNAL_ERROR: 13,
  UNSUPPORTED_APPLICATION: 14,
  DECOMPRESSION_FAILED: 15,
  PROFILE_CREATION_FAILED: 16,
  RESOURCE_RECOVERY_FAILED: 17,
  DEFAULT_DIR_ACCESS_DENIED: 18,
});

export function errorString(errorCodeToLookup) {
  for (let [errorName, errorCode] of Object.entries(ERRORS)) {
    if (errorCode == errorCodeToLookup) {
      return errorName;
    }
  }
  return "UNDEFINED_ERROR";
}

